class Solution {
public:
    int minSwaps(vector<int>& nums) {
        int n = nums.size();
        int totalOnes = 0;
        for (int i = 0; i < n; i++) {
            if (nums[i] == 1) {
                totalOnes++;
            }
        }
        if (totalOnes == 0) return 0;

        int minSwaps = n;
        for (int i = 0; i < n; i++) {
            int onesInWindow = 0;
            for (int j = i; j < i + totalOnes; j++) {
                onesInWindow += nums[j % n];
            }
            minSwaps = min(minSwaps, totalOnes - onesInWindow);
            for (int j = i + totalOnes; j < i + n; j++) {
                onesInWindow -= nums[(j - totalOnes) % n];
                onesInWindow += nums[j % n];
                minSwaps = min(minSwaps, totalOnes - onesInWindow);
            }
        }
        return minSwaps;
    }
};

